package homepractice;

public abstract class Workdemo1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		//Arithmetic Operations
		
		int h=35, d=12;
		
		System.out.println("Addition"+(h+d));
		
		System.out.println("Subtraction"+(h-d));

		System.out.println("Multiplication"+(h*d));
		
		System.out.println("Division"+(h/d));
		
		
		System.out.println("Addition of "+h+" and "+d+" is "+(h+d));

		System.out.println("Subtraction of "+h+" and "+d+" is "+(h-d));
		
		System.out.println("Multiplication of "+h+" and "+d+" is "+(h*d));
		
		System.out.println("Division of "+h+" and "+d+" is "+(h/d));



		}
	}


